main.py
import base64
import logging
from odoo import http
from odoo.http import request

_logger = logging.getLogger(__name__)

NUM_FIELDS = {
    'age': int,
    'years_in_current_position': float,
    'current_salary': float,
    'salary_expectation': float,
    'total_years_banking_exp': float,
    'interview_score': float,
    'written_exam_score': float,
}

# Accept both common website field names and model field names
ALLOWED_FIELDS = {
    # names as used in default website template
    'partner_name', 'email_from', 'partner_phone', 'job_id',
    # your custom fields (these must match name="..." in templates.xml)
    'age', 'gender',
    'educational_qualification', 'institution_name',
    'current_position', 'years_in_current_position', 'current_employer',
    'current_salary', 'salary_expectation',
    'total_years_banking_exp', 'current_location', 'preferred_location',
    # also accept some variants to be safe
    'partner_email',
}

# mapping from incoming posted name -> hr.applicant field name (if different)
NAME_MAP = {
    'email_from': 'email_from',
    'partner_email': 'email_from',   # in case the template uses this name
    'partner_name': 'partner_name',
    'partner_phone': 'partner_phone',
    'job_id': 'job_id',
    # the custom fields names are already same as model
}

class WebsiteHrRecruitmentCustom(http.Controller):

    @http.route(['/ahadu/jobs/apply_custom'], type='http', auth='public', methods=['POST'], website=True)
    def apply_custom(self, **post):
        """
        Instrumented handler: logs raw posted data, builds vals, creates hr.applicant,
        saves attachments and logs final created record id + values.
        """
        env = request.env
        _logger.info("=== Received /ahadu/jobs/apply_custom POST ===")
        # log the raw POST keys & small preview of values
        for k, v in post.items():
            # only log small values to avoid huge logs for files
            _logger.info("POST key=%s value_preview=%s", k, (v[:200] + '...') if isinstance(v, str) and len(v) > 200 else v)

        vals = {}
        # build values using either direct names or NAME_MAP
        for k, v in post.items():
            if k not in ALLOWED_FIELDS and k not in NAME_MAP:
                continue
            # resolve to a model field name
            model_field = NAME_MAP.get(k, k)

            # normalise value
            val = (v or "").strip() if isinstance(v, str) else v
            if val is None or val == '':
                # skip empty values and let model defaults apply
                continue

            # numeric casting
            if model_field in NUM_FIELDS:
                try:
                    vals[model_field] = NUM_FIELDS[model_field](val)
                except Exception:
                    _logger.warning("Failed to cast numeric field %s value=%r, defaulting to 0", model_field, val)
                    vals[model_field] = 0
            else:
                vals[model_field] = val

        # Special: ensure gender only allowed values (do not write invalid sentinel)
        if 'gender' in vals and vals.get('gender') not in ('male', 'female'):
            _logger.warning("Gender value %r not valid, removing to use model default", vals.get('gender'))
            vals.pop('gender', None)

        # Convert job_id to int if present
        if 'job_id' in vals:
            try:
                vals['job_id'] = int(vals['job_id'])
            except Exception:
                _logger.warning("job_id casting failed for %r, removing", vals.get('job_id'))
                vals.pop('job_id', None)

        _logger.info("Final vals to create hr.applicant: %s", vals)

        # create the applicant
        try:
            applicant = env['hr.applicant'].sudo().create(vals)
        except Exception as e:
            _logger.exception("Failed to create hr.applicant: %s", e)
            # fallback redirect with error (could show a message)
            return request.redirect('/jobs?error=1')

        _logger.info("Created hr.applicant id=%s name=%s", applicant.id, applicant.partner_name or applicant.name)

        # process file attachments (if any)
        files = request.httprequest.files.getlist('application_documents')
        attachment_ids = []
        for f in files:
            if not f:
                continue
            content = f.read()
            if not content:
                continue
            try:
                attachment = env['ir.attachment'].sudo().create({
                    'name': f.filename or 'attachment',
                    'datas': base64.b64encode(content),
                    'datas_fname': f.filename,
                    'mimetype': f.mimetype,
                    'res_model': 'hr.applicant',
                    'res_id': applicant.id,
                })
                attachment_ids.append(attachment.id)
            except Exception:
                _logger.exception("Failed creating attachment for applicant %s", applicant.id)

        if attachment_ids:
            applicant.sudo().write({'application_documents': [(6, 0, attachment_ids)]})
            _logger.info("Linked attachments %s to applicant %s", attachment_ids, applicant.id)

        # Log a database read-back to show what was stored
        saved = env['hr.applicant'].sudo().browse(applicant.id)
        _logger.info("Saved applicant fields: age=%s gender=%s educational_qualification=%s current_position=%s",
                     saved.age, saved.gender, saved.educational_qualification, saved.current_position)

        return request.redirect(post.get('redirect_url') or f'/jobs/{vals.get("job_id", "")}')























/** @odoo-module **/

import { registry } from "@web/core/registry";

registry.category("public_root").add("ahadu_apply_form_fix", {
    start() {
        window.addEventListener("load", function () {
            const form = document.getElementById("hr_recruitment_form");
            if (!form) return;

            const cleanAction = "/ahadu/jobs/apply_custom";

            // Remove Odoo’s ajax and data handlers if any
            form.removeAttribute("data-ajax");
            form.removeEventListener("submit", form.onsubmit);
            form.onsubmit = null;

            // Detach all jQuery event handlers (if jQuery exists)
            if (window.$) {
                try {
                    $(form).off("submit");
                } catch (err) {
                    console.warn("[Ahadu Fix] jQuery off error:", err);
                }
            }

            // Force clean action and intercept submit
            form.setAttribute("action", cleanAction);

            form.addEventListener(
                "submit",
                function (e) {
                    const current = form.getAttribute("action") || "";
                    if (current.includes("undefined")) {
                        e.preventDefault();
                        console.warn("[Ahadu Fix] Bad action found:", current);
                        form.setAttribute("action", cleanAction);
                        console.info("[Ahadu Fix] Reset to:", cleanAction);
                        form.submit();
                        return false;
                    }
                    console.info("[Ahadu Fix] Submitting to:", current);
                },
                true
            );

            console.info("[Ahadu Fix] Recruitment form handler loaded.");
        });
    },
});

setInterval(() => {
    const form = document.getElementById("hr_recruitment_form");
    if (form && form.action.includes("undefined")) {
        form.action = "/ahadu/jobs/apply_custom";
        console.warn("[Ahadu Fix] Auto-corrected bad form action.");
    }
}, 500);




main.py
import base64
import logging
import re
from odoo import http
from odoo.http import request

_logger = logging.getLogger(__name__)

NUM_FIELDS = {
    'age': int,
    'years_in_current_position': float,
    'current_salary': float,
    'salary_expectation': float,
    'total_years_banking_exp': float,
    'interview_score': float,
    'written_exam_score': float,
}

# Accept both common website field names and model field names
ALLOWED_FIELDS = {
    'partner_name', 'email_from', 'partner_phone', 'job_id',
    'age', 'gender',
    'educational_qualification', 'institution_name',
    'current_position', 'years_in_current_position', 'current_employer',
    'current_salary', 'salary_expectation',
    'total_years_banking_exp', 'current_location',
    'partner_email',
    'linkedin_profile',
}

NAME_MAP = {
    'email_from': 'email_from',
    'partner_email': 'email_from',
    'partner_name': 'partner_name',
    'partner_phone': 'partner_phone',
    'job_id': 'job_id',
}


class WebsiteHrRecruitmentCustom(http.Controller):

    @http.route(['/ahadu/jobs/apply_custom'], type='http', auth='public', methods=['POST'], website=True)
    def apply_custom(self, **post):
        env = request.env
        _logger.info("=== Received /ahadu/jobs/apply_custom POST ===")

        # Log POST keys for debugging
        for k, v in post.items():
            _logger.info(
                "POST key=%s value_preview=%s",
                k,
                (v[:200] + '...') if isinstance(v, str) and len(v) > 200 else v
            )

        vals = {}

        # Build values from POST
        for k, v in post.items():
            if k not in ALLOWED_FIELDS and k not in NAME_MAP:
                continue
            model_field = NAME_MAP.get(k, k)
            val = (v or "").strip() if isinstance(v, str) else v
            if not val:
                continue

            if model_field in NUM_FIELDS:
                try:
                    vals[model_field] = NUM_FIELDS[model_field](val)
                except Exception:
                    _logger.warning(
                        "Failed to cast numeric field %s value=%r, defaulting to 0",
                        model_field, val
                    )
                    vals[model_field] = 0
            else:
                vals[model_field] = val

        # ---------------------------------------------------------------------
        # ✅ Name validation logic (added)
        # ---------------------------------------------------------------------
        name = vals.get('partner_name', '').strip()
        if not name:
            _logger.warning("Missing name in application submission")
            return request.make_json_response({
                'success': False,
                'error': "Full name is required."
            })

        # Allow only letters, spaces, hyphens, apostrophes
        if not re.match(r"^[A-Za-zÀ-ÿ' -]{2,}$", name):
            _logger.warning("Invalid name submitted: %s", name)
            return request.make_json_response({
                'success': False,
                'error': "Please enter a valid full name (letters only)."
            })

        # Normalize gender
        if 'gender' in vals and vals['gender'] not in ('male', 'female'):
            _logger.warning("Invalid gender value %r removed", vals['gender'])
            vals.pop('gender', None)

        # Convert job_id
        if 'job_id' in vals:
            try:
                vals['job_id'] = int(vals['job_id'])
            except Exception:
                _logger.warning("job_id casting failed for %r", vals['job_id'])
                vals.pop('job_id', None)

        _logger.info("Final vals to create hr.applicant: %s", vals)

        # ---------------------------------------------------------------------
        # Ensure candidate record exists (since hr.applicant.candidate_id is required)
        # ---------------------------------------------------------------------
        try:
            email = vals.get('email_from')
            candidate = False
            if email:
                candidate = env['hr.candidate'].sudo().search(
                    [('email_from', '=', email)], limit=1
                )
            if not candidate:
                candidate_vals = {}
                if 'partner_name' in vals:
                    candidate_vals['partner_name'] = vals['partner_name']
                if email:
                    candidate_vals['email_from'] = email
                if 'partner_phone' in vals:
                    candidate_vals['partner_phone'] = vals['partner_phone']
                if 'linkedin_profile' in vals:
                    candidate_vals['linkedin_profile'] = vals['linkedin_profile']    

                _logger.info("Creating hr.candidate with values: %s", candidate_vals)
                candidate = env['hr.candidate'].sudo().create(candidate_vals)

            # LINK CANDIDATE TO APPLICANT
            vals['candidate_id'] = candidate.id
            _logger.info("Linked or created hr.candidate id=%s for applicant", candidate.id)

            # ----------------- NEW: Sync Salary Expectation -----------------
            if 'salary_expectation' in vals:
                try:
                    candidate.sudo().write({'salary_expectation': vals['salary_expectation']})
                    _logger.info(
                        "✅ Synced salary_expectation to hr.candidate.expected_salary: %s",
                        vals['salary_expectation']
                    )
                except Exception as e:
                    _logger.warning("⚠️ Failed to sync salary_expectation to candidate: %s", e)

            # Ensure linkedin_profile is set on candidate if provided (safe write)
            if 'linkedin_profile' in vals:
                try:
                    candidate.sudo().write({'linkedin_profile': vals['linkedin_profile']})
                    _logger.info("✅ Synced linkedin_profile to hr.candidate: %s", vals['linkedin_profile'])
                except Exception as e:
                    # If hr.candidate doesn't have linkedin_profile, log and continue
                    _logger.debug("hr.candidate has no linkedin_profile field; skipping candidate write: %s", e)

        except Exception as e:
            _logger.exception("Failed ensuring candidate record: %s", e)
            return request.redirect('/jobs?error=1')

        # ---------------------------------------------------------------------
        # Normalize & validate Ethiopian phone before creating applicant
        # ---------------------------------------------------------------------
        ETHIOPIAN_PHONE_REGEX = re.compile(r"^\+2519\d{8}$")  # Only normalized +2519XXXXXXXX

        phone = vals.get('partner_phone')
        if phone:
            phone = phone.strip().replace(" ", "")  # remove whitespace
            # Auto-normalize: convert 09XXXXXXXX to +2519XXXXXXXX
            if phone.startswith('09'):
                phone = '+251' + phone[1:]
            vals['partner_phone'] = phone

            # Server-side validation
            if not ETHIOPIAN_PHONE_REGEX.match(phone):
                _logger.warning("Invalid Ethiopian phone submitted: %s", phone)
                return request.make_json_response({
                    'success': False,
                    'error': "Invalid Ethiopian phone number. Use +251911123456."
                })

        # ---------------------------------------------------------------------
        # Create the applicant record
        # ---------------------------------------------------------------------
        try:
             # Mirror custom salary_expectation → Odoo default salary_expected
            if 'salary_expectation' in vals:
                vals['salary_expected'] = vals['salary_expectation']

            applicant = env['hr.applicant'].sudo().create(vals)
            _logger.info("Created hr.applicant id=%s for candidate=%s", applicant.id, vals['candidate_id'])
        except Exception as e:
            _logger.exception("Failed to create hr.applicant: %s", e)
            return request.redirect('/jobs?error=1')

        # ---------------------------------------------------------------------
        # Handle attachments — improved version (supports multiple & indexed files)
        # ---------------------------------------------------------------------
        files = []
        try:
            # Grab any file whose field name includes 'application_documents'
            for key in request.httprequest.files.keys():
                if 'application_documents' in key:
                    for f in request.httprequest.files.getlist(key):
                        if f and getattr(f, 'filename', None):
                            files.append(f)
        except Exception:
            _logger.exception("Error while collecting uploaded files")

        attachment_ids = []
        for f in files:
            try:
                content = f.read()
            except Exception:
                _logger.exception("Failed reading uploaded file %s", getattr(f, 'filename', None))
                continue
            if not content:
                _logger.warning("Uploaded file %s was empty, skipping", getattr(f, 'filename', None))
                continue

            try:
                # base64 encode binary content
                b64 = base64.b64encode(content)
                attachment_vals = {
                    'name': f.filename or 'attachment',
                    'mimetype': getattr(f, 'mimetype', None) or None,
                    'res_model': 'hr.applicant',
                    'res_id': applicant.id,
                }

                # 🧩 Dynamically use correct field name for file binary data
                if 'raw' in env['ir.attachment']._fields:
                    attachment_vals['raw'] = b64
                else:
                    attachment_vals['datas'] = b64

                attachment = env['ir.attachment'].sudo().create(attachment_vals)
                attachment_ids.append(attachment.id)
                _logger.info(
                    "✅ Created attachment '%s' (id=%s) for applicant %s",
                    f.filename, attachment.id, applicant.id
                )

            except Exception:
                _logger.exception(
                    "Failed creating attachment for applicant %s file=%s",
                    applicant.id, getattr(f, 'filename', None)
                )

        if attachment_ids:
            try:
                applicant.sudo().write({'application_documents': [(6, 0, attachment_ids)]})
                _logger.info("✅ Linked attachments %s to applicant %s", attachment_ids, applicant.id)
            except Exception:
                _logger.exception("Failed linking attachments to applicant %s", applicant.id)

        # ---------------------------------------------------------------------
        # ✅ Return JSON response
        # ---------------------------------------------------------------------
        return request.redirect('/jobs/thankyou')

    @http.route(['/jobs/thankyou'], type='http', auth='public', website=True)
    def jobs_thankyou(self, **kw):
        return request.render('ahadu_website_custom.jobs_thankyou_template')





























